import{_ as a,o as t,c as r,ag as i}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt0601.jpg",s="/images/lekt0602.jpg",c=JSON.parse('{"title":"Lektion 6","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion06.md","filePath":"lektionen/lektion06.md"}'),p={name:"lektionen/lektion06.md"};function l(d,e,u,h,o,m){return t(),r("div",null,[...e[0]||(e[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-6" tabindex="-1">Lektion 6 <a class="header-anchor" href="#lektion-6" aria-label="Permalink to &quot;Lektion 6&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>6.1. Der Verbalsatz</li><li>6.2. Zur Bildung der Verbalformen</li><li>6.3. Indikativ Präsens (laṭ = लट्)</li><li>6.4. Primärendungen der dritten Person (prathama m. = प्रथम = &quot;erste (!) Person&quot;)</li><li>6.5. Bildung des Präsensstamms <ul><li>6.5.1. Verben der 6. Präsensklasse (tudādi = तुदादि = &quot;tud usw.&quot;)</li><li>6.5.2. Verben der 1. Präsensklasse (bhvādi / bhūvādi = भ्वादि / भूवादि = &quot;bhū usw.&quot;) <ul><li>6.5.2.1. Wortsandhi von e und o</li><li>6.5.2.2. Lautabstufung (Ablaut)</li></ul></li><li>6.5.3. Verben der 4. Präsensklasse (divādi = दिवादि = &quot;div usw.&quot;)</li><li>6.5.4. Themavokal, thematische Präsensklassen</li></ul></li><li>6.6. Gesprochenes Sanskrit: Weitere Fragen (praśna m. = प्रश्न)</li><li>6.7. Wortliste</li><li>6.8. Übung</li><li>6.9. Wiederholungsübung</li></ul><h2 id="_6-1-der-verbalsatz" tabindex="-1">6.1. Der Verbalsatz <a class="header-anchor" href="#_6-1-der-verbalsatz" aria-label="Permalink to &quot;6.1. Der Verbalsatz&quot;">​</a></h2><p>Schema I: Verbalform</p><blockquote><p>z.B. yajati = यजति = &quot;Er (sie, es) verehrt mit einem Opfer&quot; &quot;Er (sie,es) opfert&quot;</p></blockquote><p>Schema II: Agens (kartṛ m. = कर्तृ) - Verbalform</p><blockquote><p>z.B. rāmo yajati =  रामो यजति = &quot;Rāma verehrt mit einem Opfer&quot; &quot;Rāma opfert&quot;</p></blockquote><p>Wird der Agens (kartṛ m. = कर्तृ) in einem Verbalsatz genannt, der nicht im Passiv steht, dann steht der Agens im Nominativ (erster Fall, prathamā = प्रथमा). Im Numerus (Zahl, vacana n. = वचन) stimmen dann Agens und Verbalform überein.</p><h2 id="_6-2-zur-bildung-der-verbalformen" tabindex="-1">6.2. Zur Bildung der Verbalformen <a class="header-anchor" href="#_6-2-zur-bildung-der-verbalformen" aria-label="Permalink to &quot;6.2. Zur Bildung der Verbalformen&quot;">​</a></h2><p>Eine finite Verbalform, d.h. eine Verbalform mit Personalendung, drückt im Sanskrit Folgendes aus:</p><ol><li>Bedeutung (artha m. अर्थ)</li><li>Person und Numerus (Zahl, vacana n. = वचन) (ich, du er &lt;sie, es&gt;, wir beide, ihr beide, sie beide, wir, ihr sie)</li><li>Verhaltensweise (genus verbi): <ol><li><p>Parasmaipada (n. = परस्मैपद) (&quot;Wortform mit Bezug auf einen anderen&quot;): Aktivum<br> z.B. yajati = यजति = &quot;Er verehr mit einem Opfer&quot; (nämlich der Priester, der für jemanden anderen das Opfer vollzieht)</p></li><li><p>Ātmanepada (n. = आत्मनेपद) (&quot;Wortform mit Bezug auf sich selbst&quot;): Medium<br> z.B. yajate = यजते = &quot;Er verehrt mit einem Opfer im eigenen Interesse&quot; (nämlich der Opferherr, der für sich und seine Familie opfert)</p></li><li><p>Passiv (karman n. = कर्मन्)<br> z.B. ijyate = इज्यते = &quot;Es wird mit einem Opfer verehrt&quot;</p><p>In vielen Fällen lässt sich die Bedeutungsnuance des Ātmanepada nicht mehr erkennen; auch verwenden selbst Kunstdichter oft das Ātmanepada ohne Bedeutungsunterschied zum Parasmaipada. Dennoch, ist bei der Übersetzung immer genau zu beachten, ob nicht eine solche Bedeutungsnuance vorliegt.</p><p>Verben, die im Parasmaipada und Ātmanepada (in der spezifischen Ātmanepada-Bedeutung) verwendet werden, nennt man Ubhayapada-Verben (ubhayapada n. = उभयपद = &quot;beide Wortformen&quot;).</p><p>Manche Verben, werden entweder nur im Parasmaipada oder nur im Ātmanepada gebraucht. Bei diesen Verben hat das Ātmanepada bzw. Parasmaipada keine spezifische Bedeutung. z.B. manyate = मन्यते = &quot;er (sie, es) denkt&quot; (ohne spezifische Ātmanepadabedeutung).</p></li><li><p>Aussageweise (Modus):</p><ol><li>Indikativ: Aussageform</li><li>Optativ: Wunschform und Möglichkeitsform</li><li>Imperativ: Befehlsform</li></ol></li><li><p>Zeit (Tempus):</p><ol><li><p>Präsens: Gegenwart</p></li><li><p>Imperfekt</p></li><li><p>Perfekt</p></li><li><p>Aorist</p></li><li><p>Futur: Zukunft</p></li><li><p>Konditional</p><p>Die Zeiten werden von Tempusstämmen gebildet: Präsensstamm, Aoriststamm, Perfektstamm, Futurstamm</p></li></ol></li></ol></li></ol><h2 id="_6-3-indikativ-prasens-lat-लट्" tabindex="-1">6.3. Indikativ Präsens (laṭ = लट्) <a class="header-anchor" href="#_6-3-indikativ-prasens-lat-लट्" aria-label="Permalink to &quot;6.3. Indikativ Präsens (laṭ = लट्)&quot;">​</a></h2><p>Das Präsens ist das Tempus der Gegenwart, insbesondere auch der Dauer.</p><p>Der Indikativ (Aussageform) Präsens wird gebildet, indem an den Präsensstamm die sogenannten Primärendungen angefügt werden</p><p>z.B.</p><p>| Wurzel</p><table tabindex="0"><thead><tr><th>(dhātu = धातु)</th><th>Präsensstamm</th><th>3. Person singular Indikativ Präsens Parasmaipada</th></tr></thead><tbody><tr><td>viś = विश्</td><td>viśa = विश</td><td>viśati = विशति = &quot;er (sie, es) tritt ein&quot;</td></tr><tr><td>bhū =  भू</td><td>bhava = भव</td><td>bhavati = भवति = &quot;er (sie, es) entsteht&quot;</td></tr><tr><td>nṛt = नृत्</td><td>nṛtya = नृत्य</td><td>nṛtyati = नृत्यति = &quot;er (sie, es) tanzt&quot;</td></tr></tbody></table><h2 id="_6-4-primarendungen-der-dritten-person-prathama-m-प्रथम-erste-person" tabindex="-1">6.4. Primärendungen der dritten Person (prathama m. = प्रथम = &quot;erste (!) Person&quot;) <a class="header-anchor" href="#_6-4-primarendungen-der-dritten-person-prathama-m-प्रथम-erste-person" aria-label="Permalink to &quot;6.4. Primärendungen der dritten Person (prathama m. = प्रथम = &quot;erste (!) Person&quot;)&quot;">​</a></h2><p>|   | Singular<br> Einzahl<br> ekavacana n.<br> एकवचन | Plural<br> Mehrzahl<br> bahuvacana n.<br> बहुवचन | | --- | --- | --- | | Parasmaipada n.<br> परस्मैपद | -ti<br> -ति | -nti<br> -न्ति | | Ātmanepada<br> आत्मनेपद | -te<br> -ते | -nte<br> -न्ते |</p><p>z.B.</p><p>yaj =  यज् = &quot;mit einem Opfer verehren&quot;, &quot;opfern&quot;</p><blockquote><p>Präsensstamm: yaja = यज</p><p>3. sg. P. yajati = यजति<br> 3. pl. P. yajanti = यजन्ति</p><p>3. sg. Ā. yajate = यजते<br> 3. pl. Ā. yajante = यजन्ते</p></blockquote><h2 id="_6-5-bildung-des-prasensstamms" tabindex="-1">6.5. Bildung des Präsensstamms <a class="header-anchor" href="#_6-5-bildung-des-prasensstamms" aria-label="Permalink to &quot;6.5. Bildung des Präsensstamms&quot;">​</a></h2><h3 id="_6-5-1-verben-der-6-prasensklasse-tudadi-तुदादि-tud-usw" tabindex="-1">6.5.1. Verben der 6. Präsensklasse (tudādi = तुदादि = &quot;tud usw.&quot;) <a class="header-anchor" href="#_6-5-1-verben-der-6-prasensklasse-tudadi-तुदादि-tud-usw" aria-label="Permalink to &quot;6.5.1. Verben der 6. Präsensklasse (tudādi = तुदादि = &quot;tud usw.&quot;)&quot;">​</a></h3><table><tbody><tr><td colspan="2">**Präsensstamm = Wurzel in Tiefstufe (in der sie aufgeführt wird) + a-**</td></tr><tr><th>Wurzel<br>dhātu m.<br>धातु</th><th>Präsensstamm</th></tr><tr><th>viś<br>विश्</th><th>viśa-<br>विश-</th></tr><tr><th>sṛj<br>सृज्</th><th>sṛja-<br>सृज</th></tr></tbody></table><h3 id="_6-5-2-verben-der-1-prasensklasse-bhvadi-bhuvadi-भ्वादि-भूवादि-bhu-usw" tabindex="-1">6.5.2. Verben der 1. Präsensklasse (bhvādi / bhūvādi = भ्वादि / भूवादि = &quot;bhū usw.&quot;) <a class="header-anchor" href="#_6-5-2-verben-der-1-prasensklasse-bhvadi-bhuvadi-भ्वादि-भूवादि-bhu-usw" aria-label="Permalink to &quot;6.5.2. Verben der 1. Präsensklasse (bhvādi / bhūvādi = भ्वादि / भूवादि = &quot;bhū usw.&quot;)&quot;">​</a></h3><table><tbody><tr><td colspan="4">**Präsensstamm = Wurzel in Hochstufe (selten Dehnstufe) + a-**</td></tr><tr><th>Wurzel<br>dhātu m.<br>धातु</th><th>Hochstufe</th><th>Hochstufe vor a-</th><th>Präsensstamm</th></tr><tr><th>bhū<br>भू</th><th>bho<br>भो</th><th>bhav<br>भव्</th><th>bhava-<br>भव-</th></tr><tr><th>nī<br>नी</th><th>ne<br>ने</th><th>nay<br>नय्</th><th>naya-<br>नय-</th></tr><tr><th>smṛ<br>स्मृ</th><th>smar<br>स्मर्</th><th>smar<br>स्मर्</th><th>smara-<br>स्मर-</th></tr><tr><th>yaj<br>यज्</th><th>yaj<br>यज्</th><th>yaj<br>यज्</th><th>yaja-<br>यज-</th></tr><tr><th colspan="4">Steht der Vokal in langer geschlossener Silbe, d.h. Kurzvokal vor zwei oder mehr Konsonanten , unterbleibt die Bildung der Hochstufe</th></tr><tr><th>nind<br>निन्द्</th><th>nind<br>निन्द्</th><th>nind<br>निन्द्</th><th>ninda-<br>निन्द-</th></tr></tbody></table><h3 id="_6-5-2-1-wortsandhi-von-e-und-o" tabindex="-1">6.5.2.1. Wortsandhi von e und o <a class="header-anchor" href="#_6-5-2-1-wortsandhi-von-e-und-o" aria-label="Permalink to &quot;6.5.2.1. Wortsandhi von e und o&quot;">​</a></h3><p>Vor Vokalen wird im Wortinnern e durch ay, o durch av ersetzt.</p><h3 id="_6-5-2-2-lautabstufung-ablaut" tabindex="-1">6.5.2.2. Lautabstufung (Ablaut) <a class="header-anchor" href="#_6-5-2-2-lautabstufung-ablaut" aria-label="Permalink to &quot;6.5.2.2. Lautabstufung (Ablaut)&quot;">​</a></h3><p>| Tiefstufe<br> Schwundstufe | Hochstufe<br> Vollstufe<br> Guṇa m.<br> गुण | Dehnstufe<br> Vṛddhi f.<br> वृद्धि | | --- | --- | --- | | ø | a | ā | | i/ī | e | ai | | u/ū | o | au | | ṛ/ṝ | ar | ār | | ḷ | al | āl |</p><h3 id="_6-5-3-verben-der-4-prasensklasse-divadi-दिवादि-div-usw" tabindex="-1">6.5.3. Verben der 4. Präsensklasse (divādi = दिवादि = &quot;div usw.&quot;) <a class="header-anchor" href="#_6-5-3-verben-der-4-prasensklasse-divadi-दिवादि-div-usw" aria-label="Permalink to &quot;6.5.3. Verben der 4. Präsensklasse (divādi = दिवादि = &quot;div usw.&quot;)&quot;">​</a></h3><table><tbody><tr><td colspan="2">**Präsensstamm = Wurzel in Tiefstufe (in der sie aufgeführt wird) + ya-**</td></tr><tr><th>Wurzel<br>dhātu m.<br>धातु</th><th>Präsensstamm</th></tr><tr><th>nṛt<br>नृत्</th><th>nṛtya-<br>नृत्य-</th></tr><tr><th>muh<br>मुह्</th><th>muhya-<br>मुह्य-</th></tr><tr><th>yudh<br>युध्</th><th>yudhya-<br>युध्य-</th></tr><tr><th>man<br>मन्</th><th>manya-<br>मन्य-</th></tr></tbody></table><h3 id="_6-5-4-themavokal-thematische-prasensklassen" tabindex="-1">6.5.4. Themavokal, thematische Präsensklassen <a class="header-anchor" href="#_6-5-4-themavokal-thematische-prasensklassen" aria-label="Permalink to &quot;6.5.4. Themavokal, thematische Präsensklassen&quot;">​</a></h3><p>Das a in den Stammbildungssuffixen von Präsensklassen nennt man Themavokal. Präsensklassen mit a im Stammbildungssuffix heißen deswegen &quot;thematische Präsensklassen&quot;.</p><h2 id="_6-6-gesprochenes-sanskrit-weitere-fragen-prasna-m-प्रश्न" tabindex="-1">6.6. Gesprochenes Sanskrit: Weitere Fragen (praśna m. = प्रश्न) <a class="header-anchor" href="#_6-6-gesprochenes-sanskrit-weitere-fragen-prasna-m-प्रश्न" aria-label="Permalink to &quot;6.6. Gesprochenes Sanskrit: Weitere Fragen (praśna m. = प्रश्न)&quot;">​</a></h2><p>N. N. kiṃ karoti? = N.N. किं करोति =&quot;Was tut N. N.?&quot;</p><p>N. N. (plural) kiṃ kurvanti? = N.N. किं कुर्वन्ति = &quot;Was tun die N.N.s.&quot;</p><p>karoti, kurvanti = करोति, कुर्वन्ति zu kṛ = कृ 8 U: &quot;tun, machen&quot;</p><p>kiṃ kuśalam? = किं कुशलम् = &quot;Geht es Ihnen gut?, Wie geht es Ihnen?&quot;</p><p>Antwort:</p><p>sarvathā kuśalam = सर्वथा कुशलम् = (Es geht mir) in jeder Hinsicht gut.</p><h2 id="_6-7-wortliste" tabindex="-1">6.7. Wortliste <a class="header-anchor" href="#_6-7-wortliste" aria-label="Permalink to &quot;6.7. Wortliste&quot;">​</a></h2><p>Im Sanskrit werden die Verben in der Wurzel-Form angeführt. Die Zahl nach der Wurzel bedeutet die Konjugationsklasse.</p><p>P: Wurzel ist nur Parasmaipada</p><p>Ā: Wurzel ist nur Ātmanepada</p><p>U: Ubhayapada (&quot;beide Wortformen&quot;): Wurzel wird im Parasmaipada und Ātmanepada verwendet, im Ātmanepada im spezifischen Ātmanepada-Sinn (wenn etwas im eigenen Interesse geschieht)</p><p>(): In Klammern steht in den Wortlisten die 3. Person (prathama) Singular Präsens Indikativ (laṭ)</p><p>Lernen Sie folgende Wörter:</p><p>yaj 1 U (yajati)  यज् यजति : mit einem Opfer verehren, opfern</p><p>bhū 1 P (bhavati)  भू भवति : werden, entstehen, sein</p><p>smṛ 1 P (smarati) स्मृ स्मरति : vergegenwärtigen, sich erinnern</p><p>nṛt 4 P (nṛtyati) नृत् नृत्यति : tanzen</p><p>nī 1 U (nayati) नी नयति: führen</p><p>man 4 Ā (manyate) मन् मन्यते: denken</p><p>muh 4 P (muhyati) मुह् मुह्यति : verwirrt sein</p><p>yudh 4 Ā (yudhyate) युध् युध्यते : kämpfen</p><p>viś 6 P (viśati) विश् विशति : eintreten</p><p>sṛj 6 P (sṛjati) सृज् सृजति : loslassen, aus sich entlassen: emanieren lassen</p><h2 id="_6-8-ubung" tabindex="-1">6.8. Übung <a class="header-anchor" href="#_6-8-ubung" aria-label="Permalink to &quot;6.8. Übung&quot;">​</a></h2><p>A) Bilden Sie mit den in Klammern angegebenen Wurzeln  durch Einsetzen Verbalsätze:</p><p>brāhmaṇas ... (yaj, nṛt, viś, man, yudh, nī, muh)</p><p>ब्राह्मणस् ... यज्, नृत्, विश्, मन्, युध्, नी, मुह्</p><p>devas ... (nṛt, yudh, smṛ, sṛj)</p><p>देवस् ... नृत्, युध्, स्मृ, सृज्</p><p>kavis ... (man, smṛ, viś)</p><p>कविस् ... मन्, स्मृ, विश्</p><p>dhenus ... (viś, bhū)</p><p>धेनुस् ... विश्, भू</p><p>B) Setzen Sie die in Übung A gebildeten Sätze in den Plural</p><p>C) Übersetzen Sie ins Sanskrit:</p><ol><li>Er verehrt mit einem Opfer. (Der Opferpriester für einen Opferherrn)</li><li>Śiva tanzt.</li><li>Rāma führt.</li><li>Śudras sind verwirrt.</li><li>Die Kṣatriyafrauen treten ein.</li><li>Der HERR lässt emanieren.</li><li>Der Kṣatriya verehrt mit einem Opfer. (als Opferherr)</li><li>Śūdrafrauen tanzen.</li><li>Kṣatriyas kämpfen.</li><li>Heilige Männer führen.</li><li>Sie erinnern sich.</li><li>Wer (fem.) tanzt?</li><li>Die (erwähnte) Brahmanin tanzt.</li></ol><p><img src="'+n+'" alt=""><br> Śivo nṛtyati<br> शिवो नृत्यति<br> Śiva Naṭarāja (नटराज):, Kadavul Hindu Temple, Kauai, Hawaii<br> [Bildquelle: Himalayan Academy Publications, Kapaa, Kauai, Hawaii / Wikipedia. -- Creative Commons- <a href="http://creativecommons.org/licenses/by-sa/2.5/" title="http://creativecommons.org/licenses/by-sa/2.5/" target="_blank" rel="noreferrer">Attribution-ShareAlike 2.5</a> - Lizenz]</p><h2 id="_6-9-wiederholungsubung" tabindex="-1">6.9. Wiederholungsübung <a class="header-anchor" href="#_6-9-wiederholungsubung" aria-label="Permalink to &quot;6.9. Wiederholungsübung&quot;">​</a></h2><p>A) Einsetzübung: Bilden Sie Fragen, auf die die Sätze, die sie nach folgenden Einsetzübungen bilden, antworten sind:</p><p>1. devas ... (īśvara, nṛt, sṛj, agni, indra)</p><p>देवस् ... ईश्वर, नृत्, सृज्, अग्नि, इन्द्र</p><p>2. (dvija, sādhu, kavi) ... brāhmaṇaḥ</p><p>द्विज, साधु, कवि ... ब्राह्मणः</p><p>3. (śruti) ... vedaḥ</p><p>श्रुति ... वेदः</p><p>4. (veda) ... śrutiḥ</p><p>वेद ... श्रुतिः</p><p>5. (brāhmaṇa, guru) ... yajanti</p><p>ब्राह्मण, गुरु ... यजन्ति</p><p>6. (devī) ... indrāṇī</p><p>देवी ... इन्द्राणी</p><p>7. (śūdra, śūdrā, devī) ... nṛtyanti</p><p>शूद्र, शूद्रा, देवी ... नृत्यन्ति</p><p>8. (kṣatriya) ... yudhyante</p><p>क्षत्रिय ... युध्यन्ते</p><p>9. (brāhmaṇa, brāhmaṇī) ... viśanti</p><p>ब्राह्मण, ब्राह्मणी ... विशन्ति</p><p>10. (guru) ... candrakīrtiḥ</p><p>गुरु ... चन्द्रकीर्तिः</p><p>11. (sādhu) ... rāmaḥ</p><p>साधु ... रामः</p><p>B)  Setzen Sie in den Plural:</p><p>1. brāhmaṇo yajati.</p><p>ब्राह्मणो यजति |</p><p>2. kaiṣā.</p><p>कैषा |</p><p>3. kṣatriyo yajate.</p><p>क्षत्रियो यजते |</p><p>4. sādhvī smarati.</p><p>साध्वी स्मरति |</p><p>5. vaiśyā muhyati.</p><p>वैशश्या मुह्यति |</p><p>6. sṛjati.</p><p>सृजति |</p><p>7. devī manyate.</p><p>देवी मन्यते |</p><p>8. gururviśati.</p><p>गुरुर्विशति |</p><p>9. ko &#39;yam.</p><p>को ऽयम् |</p><p>10. iyaṃ devī nṛtyati.</p><p>इयं देवी नृत्यति |</p><p>11. eṣa devo yudhyate.</p><p>एष देवो युध्यते |</p><p>12. sa sṛjati.</p><p>स सृजति |</p><p>13. paśurdhenuḥ.</p><p>पशुर्धेनुः |</p><p>14. keyam.</p><p>केयम् |</p><p>C) Bilden Sie das Ātmanepada zu:</p><p>1. rāmo yajati.</p><p>रामो यजति |</p><p>2. kṣatriyā nayanti.</p><p>क्षत्रिया नयन्ति |</p><p>D) Bilden Sie das Femininum zu:</p><p>1. śūdro nayati.</p><p>शूद्रो नयति |</p><p>2. sādhurviśati.</p><p>साधुर्विशति |</p><p>3. brāhmaṇaḥ smarati.</p><p>ब्राह्मणः स्मरति |</p><p>4. kṣatriyo yudhyate.</p><p>क्षत्रियो युध्यते |</p><p>5. devo guruḥ.</p><p>देवो गुरुः |</p><p>E) Übersetzen Sie:</p><p>1. devatānnapūrṇā.</p><p>देवतान्नपूर्णा |</p><p>2. śūdretarā.</p><p>शूद्रेतरा |</p><p>3. vaiśyastulādhāraḥ.</p><p>वैश्यस्तुलाधारः |</p><p>4. kavirmāghaḥ.</p><p>कविर्माघः |</p><p>5. devyumā.</p><p>देव्युमा |</p><p>6. śrutirvedaḥ.</p><p>श्रुतिर्वेदः |</p><p>7. dhenurviśati.</p><p>धेनुर्विशति |</p><p>8. guruścaitanyaḥ.</p><p>गुरुश्चैतन्यः |</p><p>9. devīndrāṇī.</p><p>देवीन्द्राणी |</p><p>10. sādhurguruḥ.</p><p>साधुर्गुरुः |</p><p>11. gururyajate.</p><p>गुरुर्यजते |</p><p>F) Übersetzen Sie ins Sanskrit:</p><ol><li><p>Rāma opfert (als Opferherr).</p></li><li><p>Durgā ist eine Göttin.</p></li><li><p>Mīnākṣī ist eine Göttin.</p><p><img src="'+s+'" alt=""><br> Mīnākṣī (मीनाक्षी), Mīnākṣī-Tempel (மீனாக்ஷி அம்மன் கோவில்), Madurai (மதுரை), Tamil Nadu (தமிழ்நாடு)<br> [Bildquelle: Wikipedia, Public domain]</p></li><li><p>Sie sind verwirrt.</p></li><li><p>Rāma ist ein heiliger Mann.</p></li><li><p>Wer ist der HERR?</p></li><li><p>Indra ist der HERR.</p></li><li><p>Die Nutztiere treten ein.</p></li><li><p>Viṣṇu lässt emanieren = Viṣṇu erschafft.</p></li><li><p>Zweimalgeborene sind gut.</p></li><li><p>Das dreifache (Wissen) ist der Sāmaveda, der Ṛgveda und der Yajurveda. (2 Möglichkeiten)</p></li><li><p>Diese Göttin ist gut.</p></li><li><p>Die fünf &quot;Qualen&quot; sind: Nichtwissen, Ichwahn, Leidenschaft (Liebe), Hass, Anhänglichkeit an den Leib. (2 Möglichkeiten)</p></li><li><p>&quot;Verweilungszustände Brahmas&quot; sind: freundliches Wohlwollen, Mitgefühl, Mitfreude, Gleichmut. (2 Möglichkeiten)</p></li><li><p>Diese Brahmanen opfern im Auftrag anderer.</p></li><li><p>Brahmanen, Kṣatriyas und Vaśyas sind Zweimalgeborene. (2 Möglichkeiten)</p></li><li><p>Die Wissenschaften (für eine Fürsten) sind: Philosophie, das dreifache (Vedawissen), Ökonomie und Politik. (2 Möglichkeiten)</p></li><li><p>Geht es Ihnen gut?</p></li><li><p>(Es geht mir) in jeder Hinsicht gut.</p></li></ol>',169)])])}const g=a(p,[["render",l]]);export{c as __pageData,g as default};
